import unicodedata
def nfc(s):
    return unicodedata.normalize("NFC", s)
print(nfc("Jose\u0301") == nfc("José"))

import unicodedata
def fingerprint(s):
    return unicodedata.normalize("NFC", s).casefold().strip()
print(fingerprint("  MAÑANA  "), fingerprint("mañana"))

def split_name(raw):
    toks = raw.split()
    if len(toks) < 2:
        return {"raw": raw, "status": "review", "given": None, "apellidos": None}
    return {"raw": raw, "status": "ok", "given": " ".join(toks[:-2]) if len(toks) > 2 else toks[0],
            "apellidos": toks[-2:] if len(toks) >= 2 else toks}
print(split_name("Ana"))
print(split_name("Ana Quispe Huamán"))

particulas = {"de", "del", "la", "los", "las", "y"}
def tokens_name(s):
    return [t for t in s.split() if t.casefold() not in particulas or True]
# demo: mantener particulas en given
raw = "María del Carmen Quispe"
print(raw.split())

def normalize_address(raw):
    return " ".join(raw.strip().split())
print(normalize_address("  Jr.   Ucayali  100 "))

def normalize_email(raw: str) -> str:
    s = raw.strip().casefold()
    if s.count("@") != 1 or any(ch.isspace() for ch in s):
        raise ValueError("email requiere un @ y cero espacios")
    local, domain = s.split("@")
    if not local or not domain:
        raise ValueError("email requiere local y dominio")
    return s
print(normalize_email("  Ana+test@Example.COM "))

def normalize_phone_pe(raw: str) -> str:
    return "".join(c for c in raw if c.isdigit())
print(normalize_phone_pe("+51 999-000-111"))

def validate_contact(email=None, phone=None):
    errors = []
    if email is not None and email.count("@") != 1:
        errors.append("email")
    if phone is not None and not any(ch.isdigit() for ch in phone):
        errors.append("phone")
    return errors
print(validate_contact("a@b.com", "999"), validate_contact("bad", "xxx"))

def token_jaccard(a: str, b: str) -> float:
    A = set(a.replace(".", " ").casefold().split())
    B = set(b.replace(".", " ").casefold().split())
    if not A and not B:
        return 1.0
    if not A or not B:
        return 0.0
    return len(A & B) / len(A | B)
print(round(token_jaccard("Juan Perez", "Juan P. Perez"), 3))

def token_jaccard(a, b):
    A, B = set(a.casefold().split()), set(b.casefold().split())
    if not A or not B:
        return 0.0
    return len(A & B) / len(A | B)
print(round(token_jaccard("Ana Quispe", "Luis Huamán"), 3))

def decide_name_match(score):
    if score >= 0.99:
        return "exact"
    if score >= 0.5:
        return "review"
    return "no_match"
print(decide_name_match(1.0), decide_name_match(0.67), decide_name_match(0.1))

def keep_evidence(raw_a, raw_b, score, decision):
    return {"raw_a": raw_a, "raw_b": raw_b, "score": score, "decision": decision,
            "legal_claim": False}
print(keep_evidence("Ana", "Ana Quispe", 0.5, "review"))
